mapper.insert:
/* adm-common-excel-sql-oracle.xml - insertJob */
INSERT INTO TADMIN_INFO_EXCEL_JOB (
      JOBID
    , MEKEY
    , SEARCHCOND
    , STATUS
    , INSERTURKEY
    , INSERTDATE
) VALUES (
      #{jobId}
    , #{mekey}
    , #{searchcond}
    , #{status}
    , #{surkey}
    , #{sysdate}
)

mapper.select:
/* adm-common-excel-sql-oracle.xml - selectExcelJob */
SELECT COUNT(1)
  FROM TADMIN_INFO_EXCEL_JOB
 WHERE JOBID = #{jobId}
   AND STATUS = #{status}

mapper.update:
/* adm-common-excel-sql-oracle.xml - updateJob */
UPDATE TADMIN_INFO_EXCEL_JOB
   SET STATUS      = #{status}

         , FILENM = #{filenm}


        , ERRMSG = #{errmsg}

    ,  UPDATEDATE  = #{sysdate}
    ,  UPDATEURKEY = #{updateurkey}
 WHERE JOBID = #{jobId}
